#ifndef AST_BUILDER_H
#define AST_BUILDER_H

#include "asg/Asg.h"
#include <nlohmann/json.hpp>
#include "antlr4-runtime.h"

using namespace asg;
using json = nlohmann::json;

class ASTBuilder {
public:
    // Function to build JSON from ASG nodes
    json buildJSON(const Node* node) const;

    // AST node creation functions
    FunctionDecl* makeFunction(antlr4::ParserRuleContext* declCtx, antlr4::ParserRuleContext* bodyCtx) const;
    std::vector<Decl*> makeDeclaration(antlr4::ParserRuleContext* specCtx, antlr4::ParserRuleContext* initCtx) const;

private:
    // Helper functions for specific node types
    json buildFunctionDecl(const FunctionDecl* node) const;
    json buildVarDecl(const VarDecl* node) const;
    json buildCompoundStmt(const CompoundStmt* node) const;
    json buildExpr(const Expr* expr) const;
};

#endif // AST_BUILDER_H

